formulas.expression:
IF(
    {!SW_Fit_Score_Timestamp_2100} >= 
    IF(
        AND(
            ISBLANK({!Intent_First_Medium_Date_2100}),
            ISBLANK({!Intent_First_High_Date_2100})
        ),
        DATETIMEVALUE("1900-01-01 00:00:00"),
        IF(
            AND(
                ISBLANK({!Intent_First_Medium_Date_2100}),
                NOT(ISBLANK({!Intent_First_High_Date_2100}))
            ),
            {!Intent_First_High_Date_2100},
            IF(
                AND(
                    ISBLANK({!Intent_First_High_Date_2100}),
                    NOT(ISBLANK({!Intent_First_Medium_Date_2100}))
                ),
                {!Intent_First_Medium_Date_2100},
                IF(
                    {!Intent_First_Medium_Date_2100} > {!Intent_First_High_Date_2100},
                    {!Intent_First_Medium_Date_2100},
                    {!Intent_First_High_Date_2100}
                )
            )
        )
    ),
    {!SW_Fit_Score_Timestamp_2100},
    IF(
        AND(
            ISBLANK({!Intent_First_Medium_Date_2100}),
            NOT(ISBLANK({!Intent_First_High_Date_2100}))
        ),
        {!Intent_First_High_Date_2100},
        IF(
            AND(
                ISBLANK({!Intent_First_High_Date_2100}),
                NOT(ISBLANK({!Intent_First_Medium_Date_2100}))
            ),
            {!Intent_First_Medium_Date_2100},
            IF(
                {!Intent_First_Medium_Date_2100} < {!Intent_First_High_Date_2100},
                {!Intent_First_Medium_Date_2100},
                {!Intent_First_High_Date_2100}
            )
        )
    )
)
